// Persistent — Hibernate tracks changes
entityManager.persist(user); // INSERT on flush
user.setEmail("alice@example.com"); // auto-flushed as UPDATE

// Detached — Session closed
entityManager.detach(user);
user.setEmail("new@example.com"); // ignored by Hibernate

// Merge detached entity back
User managed = entityManager.merge(user); // SELECT + UPDATE

@Entity
public class Product {
    @Id Long id;
    String name;
    int stock;

    @Version
    int version; // Hibernate manages this automatically
}

// Hibernate generates:
// UPDATE product SET stock=?, version=2 WHERE id=? AND version=1
// → 0 rows updated = OptimisticLockException

public interface UserRepository extends JpaRepository<User, Long> {

    // JPQL — entity field names, not column names
    @Query("SELECT u FROM User u WHERE u.role = :role ORDER BY u.createdAt DESC")
    List<User> findByRoleOrdered(@Param("role") String role);

    // Modifying JPQL
    @Modifying
    @Transactional
    @Query("UPDATE User u SET u.lastLogin = :now WHERE u.id = :id")
    int updateLastLogin(@Param("id") Long id, @Param("now") Instant now);
}

